(function(){
  'use strict';
  const lightbox = document.getElementById('lightbox');
  if(!lightbox) return;
  const lbImg    = lightbox.querySelector('#lightbox-img');
  const lbClose  = lightbox.querySelector('#lightbox-close');
  const lbPrev   = lightbox.querySelector('#lightbox-prev');
  const lbNext   = lightbox.querySelector('#lightbox-next');
  const lbCaption= lightbox.querySelector('#lightbox-caption');
  let images = [];
  let currentIndex = 0;
  function openLightbox(index){
    currentIndex = index;
    const item = images[index];
    lbImg.src = item.large;
    lbImg.alt = item.alt;
    if(lbCaption) lbCaption.textContent = item.alt;
    lightbox.classList.add('active');
    document.body.style.overflow='hidden';
  }
  function closeLightbox(){
    lightbox.classList.remove('active');
    document.body.style.overflow='';
    lbImg.src='';
  }
  function navigate(dir){
    currentIndex = (currentIndex + dir + images.length) % images.length;
    openLightbox(currentIndex);
  }
  document.querySelectorAll('.gallery-item').forEach(function(item, idx){
    const thumb = item.querySelector('img');
    const large = item.dataset.large || thumb.src;
    const alt   = thumb.alt || ('Obrázek ' + (idx+1));
    images.push({large: large, alt: alt});
    item.addEventListener('click', function(){ openLightbox(idx); });
    item.setAttribute('role','button');
    item.setAttribute('tabindex','0');
    item.addEventListener('keydown', function(e){
      if(e.key==='Enter'||e.key===' '){ e.preventDefault(); openLightbox(idx); }
    });
  });
  if(lbClose) lbClose.addEventListener('click', closeLightbox);
  if(lbPrev)  lbPrev.addEventListener('click', function(){ navigate(-1); });
  if(lbNext)  lbNext.addEventListener('click', function(){ navigate(1); });
  lightbox.addEventListener('click', function(e){
    if(e.target === lightbox) closeLightbox();
  });
  document.addEventListener('keydown', function(e){
    if(!lightbox.classList.contains('active')) return;
    if(e.key==='Escape') closeLightbox();
    if(e.key==='ArrowLeft') navigate(-1);
    if(e.key==='ArrowRight') navigate(1);
  });
  let touchStartX = 0;
  lightbox.addEventListener('touchstart',function(e){ touchStartX=e.changedTouches[0].clientX; },{passive:true});
  lightbox.addEventListener('touchend',function(e){
    const dx = e.changedTouches[0].clientX - touchStartX;
    if(Math.abs(dx)>50) navigate(dx < 0 ? 1 : -1);
  },{passive:true});
  const dpInput = document.getElementById('meeting-date');
  if(dpInput){
    dpInput.min = new Date().toISOString().split('T')[0];
    dpInput.addEventListener('change',function(){
      const d = new Date(this.value);
      const day = d.getDay();
      if(day===0||day===6){
        alert('Konzultace jsou dostupné v pracovní dny (Po–Pá). Vyberte prosím jiný termín.');
        this.value='';
      }
    });
  }
  const form = document.getElementById('contact-form');
  if(form){
    form.addEventListener('submit',function(e){
      e.preventDefault();
      const btn = form.querySelector('.btn-submit');
      const success = document.getElementById('form-success');
      btn.textContent='Odesílám...';
      btn.disabled=true;
      setTimeout(function(){
        form.reset();
        btn.textContent='Odeslat zprávu';
        btn.disabled=false;
        if(success){ success.classList.add('show'); }
        if(window.showNotification) window.showNotification('✅ Zpráva odeslána! Ozveme se do 24 hodin.');
        setTimeout(function(){ if(success) success.classList.remove('show'); },6000);
      },1500);
    });
  }
})();